import { Component, EventEmitter, h, Prop, Event, Element, State } from '@stencil/core';
import { customTwMerge } from '../../utils/utils';

export type PageHeaderBackground = 'transparent' | 'primary' | 'secondary' | 'media' | 'translucent';

type SlotKey = 'leading' | 'trailing' | 'middle' | 'below';

@Component({
  tag: 'wdpr-page-header',
  shadow: true,
  styles: ':host { display: block; width: 100%; }'
})
export class WdprPageHeader {
  @State() slots: Record<SlotKey, boolean> = {
    leading: false,
    trailing: false,
    middle: false,
    below: false,
  };

  private leadingIconSlot!: HTMLSlotElement;
  private trailingIconSlot!: HTMLSlotElement;
  private middleSlot!: HTMLSlotElement;
  private belowSlot!: HTMLSlotElement;

  /**
   * Reference to host element
   */
  @Element() el: HTMLElement;

  /**
   * The title text to be displayed in the header.
   */
  @Prop() titleText = '';

  /**
   * Controls the aria-live attribute for the title text.
   */
  @Prop() ariaLiveMode?: 'off' | 'polite' | 'assertive' = 'off';

  @Prop() sticky: boolean = false;

  @Prop() background: PageHeaderBackground = 'primary';

  @Prop() showElevation: boolean = false;

  /**
   * If true, sets the content color to inverse (light text) for dark backgrounds.
   */
  @Prop() inverse: boolean = false;

  /**
   * On left icon click event
   */
  @Event({ eventName: 'leadingClick' }) leadingClick: EventEmitter<boolean>;

  /**
   * On right icon click event
   */
  @Event({ eventName: 'trailingClick' }) trailingClick: EventEmitter<boolean>;


  private _slotHasContent(slot?: HTMLSlotElement): boolean {
    if (!slot) return false;

    return slot.assignedElements({ flatten: true }).length > 0;
  }

  private _setSlot(key: SlotKey, value: boolean) {
    if (this.slots[key] === value) return;
    this.slots = { ...this.slots, [key]: value };
  }

  private _onClickLeadingIcon = () => {
    if (this.slots.leading) {
      this.leadingClick.emit(true);
    }
  };

  private _onClickTrailingIcon = () => {
    if (this.slots.trailing) {
      this.trailingClick.emit(true);
    }
  };

  private _getContainerClass() {
    const stickyClass = this.sticky ? 'sticky top-0 z-10' : '';

    const backgroundClassMap: Record<PageHeaderBackground, string> = {
      transparent: 'bg-surface-transparent',
      primary: 'bg-page-default',
      secondary: 'bg-page-default-alt',
      media: '',
      translucent: 'bg-surface-translucent', 
    };

    const mergedClasses = customTwMerge(
      outerContainerClass,
      stickyClass,
      backgroundClassMap[this.background]
    );

    return this.showElevation 
      ? `${mergedClasses} elevation-xsmall-soft relative z-10` 
      : mergedClasses;
  }

  private _getContainerStyle() {
    if (this.background === 'translucent') {
      return {
        backdropFilter: 'blur(calc(var(--effect-400, 32px) / 2))',
        WebkitBackdropFilter: 'blur(calc(var(--effect-400, 32px) / 2))'
      };
    }

    return {};
  }

  componentWillLoad() {
    this.slots = {
      leading: !!this.el.querySelector('[slot="leading-icon"]'),
      trailing: !!this.el.querySelector('[slot="trailing-icon"]'),
      middle: !!this.el.querySelector('[slot="middle"]'),
      below: !!this.el.querySelector('[slot="below"]'),
    };
  }

  render() {
    const titleColorClass = this.inverse ? 'text-text-inverse' : 'text-text-heading';
    const iconColorClass = this.inverse ? 'text-text-inverse' : 'text-stroke-actionable-default';

    return (
      <div class={this._getContainerClass()} style={this._getContainerStyle()}>
        <div class={containerClass}>
          <section class={leftIconContainerClass}>
            <div

              class={`${iconClass} ${iconColorClass} ${this.slots.leading ? 'inline-flex' : 'hidden'}`}
              onClick={this._onClickLeadingIcon}
            >
              <slot
                name="leading-icon"
                ref={el => (this.leadingIconSlot = el as HTMLSlotElement)}
                onSlotchange={() => this._setSlot('leading', this._slotHasContent(this.leadingIconSlot))}
              />
            </div>
          </section>

          <div class={middleContainerClass}>
            <slot
              name="middle"
              ref={el => (this.middleSlot = el as HTMLSlotElement)}
              onSlotchange={() => this._setSlot('middle', this._slotHasContent(this.middleSlot))}
            />

            {!this.slots.middle && (
              <h1
                class={`${titleClass} ${titleColorClass}`}
                aria-live={this.ariaLiveMode}
                aria-atomic={this.ariaLiveMode !== 'off' ? 'true' : 'false'}
              >
                {this.titleText}
              </h1>
            )}
          </div>

          <section class={rightIconContainerClass}>
            <div
              class={`${iconClass} ${iconColorClass} ${this.slots.trailing ? 'inline-flex' : 'hidden'}`}
              onClick={this._onClickTrailingIcon}
            >
              <slot
                name="trailing-icon"
                ref={el => (this.trailingIconSlot = el as HTMLSlotElement)}
                onSlotchange={() => this._setSlot('trailing', this._slotHasContent(this.trailingIconSlot))}
              />
            </div>
          </section>
        </div>

        <div class={`${belowContainerClass} ${this.slots.below ? 'block' : 'hidden'}`}>
          <slot
            name="below"
            ref={el => (this.belowSlot = el as HTMLSlotElement)}
            onSlotchange={() => this._setSlot('below', this._slotHasContent(this.belowSlot))}
          />
        </div>
      </div>
    );
  }
}

const outerContainerClass = 'w-full overflow-visible';
const containerClass = 'flex w-full items-center px-100';
const leftIconContainerClass = 'flex flex-1 items-center justify-start';
const rightIconContainerClass = 'flex flex-1 items-center justify-end';
const middleContainerClass = 'flex-[2] min-w-0 flex items-center justify-center';
const belowContainerClass = 'px-100 pt-100 pb-100';
const iconClass = 'items-center cursor-pointer p-200';
const titleClass =
  'min-w-0 text-center heading-xsmall overflow-hidden text-ellipsis ' +
  '[display:-webkit-box] [-webkit-line-clamp:1] [-webkit-box-orient:vertical]';
